import{_ as a,o as l,c as r,a2 as t}from"./chunks/framework.QoSTM79V.js";const _=JSON.parse('{"title":"Sprint 规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/product/02-sprint.md","filePath":"mango-pmo/rules/product/02-sprint.md"}'),e={name:"mango-pmo/rules/product/02-sprint.md"};function n(o,i,p,s,h,u){return l(),r("div",null,[...i[0]||(i[0]=[t('<h1 id="sprint-规范" tabindex="-1">Sprint 规范 <a class="header-anchor" href="#sprint-规范" aria-label="Permalink to &quot;Sprint 规范&quot;">​</a></h1><h2 id="_1-适用范围" tabindex="-1">1. 适用范围 <a class="header-anchor" href="#_1-适用范围" aria-label="Permalink to &quot;1. 适用范围&quot;">​</a></h2><ul><li>适用于 Mango 框架、平台能力、模板、CLI、前端包等 Mango 开发任务。</li><li>适用于基于 Mango 的企业业务项目、业务模块和业务后台开发任务。</li></ul><h2 id="_2-定义" tabindex="-1">2. 定义 <a class="header-anchor" href="#_2-定义" aria-label="Permalink to &quot;2. 定义&quot;">​</a></h2><ul><li>一个 Sprint 只解决一组明确问题。</li><li>一个 Sprint 必须可提交、可验证、可说明结果。</li><li>不做只完成一半的 Sprint。</li></ul><h2 id="_3-拆分规则" tabindex="-1">3. 拆分规则 <a class="header-anchor" href="#_3-拆分规则" aria-label="Permalink to &quot;3. 拆分规则&quot;">​</a></h2><ul><li>先拆边界，再拆实现。</li><li>一个 Sprint 只保留一个主目标。</li><li>超出主目标的内容移到后续 Sprint。</li><li>历史问题只处理本次范围直接相关部分。</li></ul><h2 id="_4-sprint-文档" tabindex="-1">4. Sprint 文档 <a class="header-anchor" href="#_4-sprint-文档" aria-label="Permalink to &quot;4. Sprint 文档&quot;">​</a></h2><p>Sprint 文档必须写清：</p><ul><li>背景</li><li>目标</li><li>范围</li><li>改动项</li><li>验证方式</li><li>完成标准</li><li>遗留问题</li></ul><h2 id="_5-完成标准" tabindex="-1">5. 完成标准 <a class="header-anchor" href="#_5-完成标准" aria-label="Permalink to &quot;5. 完成标准&quot;">​</a></h2><p>至少满足：</p><ul><li>代码已完成</li><li>对应验证已执行</li><li>文档状态已更新</li><li>遗留问题已记录</li></ul><h2 id="_6-禁止事项" tabindex="-1">6. 禁止事项 <a class="header-anchor" href="#_6-禁止事项" aria-label="Permalink to &quot;6. 禁止事项&quot;">​</a></h2><ul><li>一个 Sprint 放多个无关目标</li><li>代码已合并但文档状态不更新</li><li>没有验证记录就标记完成</li></ul>',15)])])}const c=a(e,[["render",n]]);export{_ as __pageData,c as default};
